udt:














.submarine-routes {
    auto-size: grow;
    flow: vertical;
    gap: 4;
    overflow: scroll;
}

.submarine-route-row {
    auto-size: grow fit;
    gap: 8;
    padding: 4;

    &:hover { background-color: 0x10FFFFFF; border-radius: 4; }
}

.submarine-sector-name {
    auto-size: grow fit;
    anchor: middle-left;
}

.submarine-gilhr {
    auto-size: fit;
    anchor: middle-right;
    color: 0xFFFFD700;
    font-size: 13;
}

.submarine-rank {
    auto-size: fit;
    anchor: middle-right;
    font-size: 11;
    color: 0xFF909090;
}

.submarine-empty {
    auto-size: grow;
    flow: vertical;
    gap: 12;
    anchor: middle-center;
    padding: 40 0;
}
